={{ (() => {
  const src = $('set d8swfnb44q clip params').item.json || {};
  const workflowRaw = $json.workflow;

  const clone = (v) => JSON.parse(JSON.stringify(v));
  const root = typeof workflowRaw === 'string' ? JSON.parse(workflowRaw) : clone(workflowRaw);
  const nodes = root && root.prompt && typeof root.prompt === 'object' ? root.prompt : root;

  const hasNode = (id) => nodes && nodes[String(id)] !== undefined;
  const actions = [];

  const patchNode = (id, mutator) => {
    const k = String(id);
    if (!hasNode(k)) return;
    const node = clone(nodes[k]);
    mutator(node);
    actions.push({
      type: 'addNode',
      id: k,
      overwrite: true,
      node
    });
  };

  const parseArr = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v === 'string') {
      try {
        const p = JSON.parse(v);
        return Array.isArray(p) ? p : [];
      } catch {
        return [];
      }
    }
    return [];
  };

  // ========= ВХОДНЫЕ ПЕРЕМЕННЫЕ =========
  const prompts = parseArr(src.chunksPositivePrompts);
  const frames = parseArr(src.chunksFramesCount);

  const startFrameFileName = src.startFrameFileName;
  const negativePrompt = src.negativePrompt ?? src.negativePrompts ?? '';

  const clipWidth = Number(src.clipWidth);
  const clipHeight = Number(src.clipHeight);
  const clipAspectRatioRaw = String(src.clipAspectRatio);

  const highNoiseSize = Number(src.highNoiseSize ?? Math.max(clipWidth, clipHeight));
  const finalSize = Number(src.finalSize ?? Math.max(clipWidth, clipHeight));

  // Сколько кадров добавлять к чанкам со 2-го и далее (для компенсации overlap)
  const OVERLAP_COMPENSATION_FRAMES = Number(src.overlapCompensationFrames ?? 6);
  // ======================================

  // target chunks: explicit > длины массивов
  const explicitCount = Number(src.chunksCount ?? src.targetChunks ?? src.totalChunks);
  let targetChunks = Number.isInteger(explicitCount) && explicitCount > 0
    ? explicitCount
    : Math.max(prompts.length, frames.length, 1);

  targetChunks = Math.max(1, Math.min(6, targetChunks));

  // Удаляем лишние чанки > targetChunks
  for (let c = targetChunks + 1; c <= 6; c++) {
    const start = c * 100;
    const end = start + 99;
    for (let id = start; id <= end; id++) {
      if (hasNode(id)) {
        actions.push({ type: 'removeNode', nodeId: String(id) });
      }
    }
  }

  // Base patches
  if (startFrameFileName) {
    patchNode(6, (n) => { n.inputs.image = String(startFrameFileName); }); // Load Image
  }

  patchNode(31, (n) => { n.inputs.text = String(negativePrompt); }); // Negative_Prompt

  // Aspect ratio node
  const ratioKeys = ['1:1','4:3','3:2','5:4','16:9','16:10','21:9','2:1','1.85:1','2.39:1'];
  const clipAspectRatio = ratioKeys.includes(clipAspectRatioRaw) ? clipAspectRatioRaw : '16:9';

  patchNode(42, (n) => {
    if (Number.isFinite(clipWidth) && clipWidth > 0) n.inputs.width = Math.round(clipWidth);
    if (Number.isFinite(clipHeight) && clipHeight > 0) n.inputs.height = Math.round(clipHeight);
    for (const k of ratioKeys) n.inputs[k] = (k === clipAspectRatio);
  });

  if (Number.isFinite(highNoiseSize) && highNoiseSize > 0) {
    patchNode(43, (n) => { n.inputs.size = Math.round(highNoiseSize); }); // Set_High_Noise_Size
  }

  if (Number.isFinite(finalSize) && finalSize > 0) {
    patchNode(44, (n) => { n.inputs.size = Math.round(finalSize); }); // Set_Final_Size
  }

  // Chunk node id maps
  const promptId = (c) => (c === 1 ? 133 : c * 100 + 44); // 133,244,344...
  const framesId = (c) => (c === 1 ? 145 : c * 100 + 51); // 145,251,351...
  const finalId  = (c) => (c === 1 ? 139 : c * 100 + 39); // 139,239,339...

  // Patch prompts + frames (со 2-го чанка добавляем overlap compensation)
  for (let c = 1; c <= targetChunks; c++) {
    const p = prompts[c - 1];
    if (p !== undefined && p !== null && hasNode(promptId(c))) {
      patchNode(promptId(c), (n) => { n.inputs.value = String(p); });
    }

    const f = Number(frames[c - 1]);
    if (Number.isFinite(f) && f > 0 && hasNode(framesId(c))) {
      const extra = c === 1 ? 0 : Math.max(0, Math.round(OVERLAP_COMPENSATION_FRAMES));
      patchNode(framesId(c), (n) => { n.inputs.value = Math.round(f) + extra; });
    }
  }

  // save_output=true только у последнего чанка
  for (let c = 1; c <= targetChunks; c++) {
    if (hasNode(finalId(c))) {
      patchNode(finalId(c), (n) => { n.inputs.save_output = (c === targetChunks); });
    }
  }

  return actions;
})() }}

={{ (() => {
  const paramsNodeName = 'set liqhn0gkqo clip params';

  const clone = (v) => JSON.parse(JSON.stringify(v));

  const fail = (message, extra = {}) => {
    return [
      {
        json: {
          ok: false,
          error: message,
          ...extra
        }
      }
    ];
  };

  let src;
  try {
    src = $(paramsNodeName).first().json || {};
  } catch (e) {
    return fail(
      `Не удалось получить данные из ноды "${paramsNodeName}" через .first().json`,
      { details: String(e.message || e) }
    );
  }

  const workflowRaw = $json.workflow;

  if (workflowRaw === undefined || workflowRaw === null || workflowRaw === '') {
    return fail('Отсутствует $json.workflow', { src });
  }

  let root;
  try {
    root = typeof workflowRaw === 'string' ? JSON.parse(workflowRaw) : clone(workflowRaw);
  } catch (e) {
    return fail('Не удалось распарсить workflow', {
      details: String(e.message || e),
      workflowType: typeof workflowRaw,
      workflowPreview: typeof workflowRaw === 'string' ? workflowRaw.slice(0, 1000) : workflowRaw
    });
  }

  const nodes = root && root.prompt && typeof root.prompt === 'object' ? root.prompt : root;

  if (!nodes || typeof nodes !== 'object' || Array.isArray(nodes)) {
    return fail('Workflow имеет некорректную структуру', { nodes });
  }

  const hasNode = (id) => nodes[String(id)] !== undefined;
  const existingNodeIds = Object.keys(nodes).sort((a, b) => Number(a) - Number(b));
  const actions = [];
  const missingWorkflowNodes = [];

  const patchNode = (id, mutator, label = '') => {
    const k = String(id);

    if (!hasNode(k)) {
      missingWorkflowNodes.push({
        id: k,
        label
      });
      return;
    }

    const node = clone(nodes[k]);
    mutator(node);

    actions.push({
      type: 'addNode',
      id: k,
      overwrite: true,
      node
    });
  };

  const isMissing = (v) => v === undefined || v === null || v === '';
  const isBadNumber = (v) => !Number.isFinite(v) || v <= 0;

  // ==================================================
  // ВХОДНЫЕ ПЕРЕМЕННЫЕ ПОД ТВОЙ РЕАЛЬНЫЙ OUTPUT
  // ==================================================
  const startFrameFileName = src.startFrameFileName;

  const positivePrompt =
    src.positivePrompt ??
    src.prompt ??
    src.clipPrompt ??
    src.chunksPositivePrompts;

  const negativePrompt =
    src.negativePrompt ??
    src.negativePrompts;

  const clipWidth = Number(src.clipWidth);
  const clipHeight = Number(src.clipHeight);

  const frameRate = Number(
    src.frameRate ??
    src.fps ??
    src.clipFrameRate ??
    24
  );

  const framesCount = Number(
    src.framesCount ??
    src.clipFramesCount ??
    src.length ??
    src.totalFrames ??
    src.chunksFramesCount
  );

  const highNoiseSeed =
    src.highNoiseSeed ?? src.seedHigh ?? src.seed1 ?? src.seed;

  const lowNoiseSeed =
    src.lowNoiseSeed ?? src.seedLow ?? src.seed2 ?? src.seed;
  // ==================================================

  const missingFields = [];

  if (isMissing(startFrameFileName)) {
    missingFields.push('startFrameFileName');
  }

  if (isMissing(positivePrompt)) {
    missingFields.push('positivePrompt | prompt | clipPrompt | chunksPositivePrompts');
  }

  if (isMissing(negativePrompt)) {
    missingFields.push('negativePrompt | negativePrompts');
  }

  if (isBadNumber(clipWidth)) {
    missingFields.push('clipWidth');
  }

  if (isBadNumber(clipHeight)) {
    missingFields.push('clipHeight');
  }

  if (isBadNumber(frameRate)) {
    missingFields.push('frameRate | fps | clipFrameRate');
  }

  if (isBadNumber(framesCount)) {
    missingFields.push('framesCount | clipFramesCount | length | totalFrames | chunksFramesCount');
  }

  if (missingFields.length > 0) {
    return fail('Не хватает обязательных входных полей', {
      missingFields,
      src,
      resolvedValues: {
        startFrameFileName,
        positivePrompt,
        negativePrompt,
        clipWidth,
        clipHeight,
        frameRate,
        framesCount,
        highNoiseSeed,
        lowNoiseSeed
      }
    });
  }

  // 269 = Load Image
  patchNode(269, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.image = String(startFrameFileName);
  }, 'Load Image');

  // 315 = Negative Prompt
  patchNode(315, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.text = String(negativePrompt);
  }, 'Negative Prompt');

  // 320 = Prompt
  patchNode(320, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = String(positivePrompt);
  }, 'Positive Prompt');

  // 314 = Width
  patchNode(314, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(clipWidth);
  }, 'Width');

  // 301 = Height
  patchNode(301, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(clipHeight);
  }, 'Height');

  // 302 = Frame Rate
  patchNode(302, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(frameRate);
  }, 'Frame Rate');

  // 303 = Length / Frames Count
  patchNode(303, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(framesCount);
  }, 'Frames Count');

  // 278 = RandomNoise
  if (!isMissing(highNoiseSeed)) {
    const seedNum = Number(highNoiseSeed);
    if (!Number.isFinite(seedNum)) {
      return fail('highNoiseSeed | seedHigh | seed1 | seed не является числом', {
        value: highNoiseSeed,
        src
      });
    }

    patchNode(278, (n) => {
      if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
      n.inputs.noise_seed = Math.round(seedNum);
    }, 'High Noise Seed');
  }

  // 279 = RandomNoise
  if (!isMissing(lowNoiseSeed)) {
    const seedNum = Number(lowNoiseSeed);
    if (!Number.isFinite(seedNum)) {
      return fail('lowNoiseSeed | seedLow | seed2 | seed не является числом', {
        value: lowNoiseSeed,
        src
      });
    }

    patchNode(279, (n) => {
      if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
      n.inputs.noise_seed = Math.round(seedNum);
    }, 'Low Noise Seed');
  }

  if (missingWorkflowNodes.length > 0) {
    return fail('В workflow отсутствуют нужные ноды', {
      missingWorkflowNodes,
      existingNodeIds,
      actions
    });
  }

  return actions;
})() }}

