={{ (() => {
  const paramsNodeName = 'set liqhn0gkqo clip params1';

  const clone = (v) => JSON.parse(JSON.stringify(v));

  const fail = (message, extra = {}) => {
    return [
      {
        json: {
          ok: false,
          error: message,
          ...extra
        }
      }
    ];
  };

  let src;
  try {
    src = $(paramsNodeName).first().json || {};
  } catch (e) {
    return fail(
      `Не удалось получить данные из ноды "${paramsNodeName}" через .first().json`,
      { details: String(e.message || e) }
    );
  }

  const workflowRaw = $json.workflow;

  if (workflowRaw === undefined || workflowRaw === null || workflowRaw === '') {
    return fail('Отсутствует $json.workflow', { src });
  }

  let root;
  try {
    root = typeof workflowRaw === 'string' ? JSON.parse(workflowRaw) : clone(workflowRaw);
  } catch (e) {
    return fail('Не удалось распарсить workflow', {
      details: String(e.message || e),
      workflowType: typeof workflowRaw,
      workflowPreview: typeof workflowRaw === 'string' ? workflowRaw.slice(0, 1000) : workflowRaw
    });
  }

  const nodes = root && root.prompt && typeof root.prompt === 'object' ? root.prompt : root;

  if (!nodes || typeof nodes !== 'object' || Array.isArray(nodes)) {
    return fail('Workflow имеет некорректную структуру', { nodes });
  }

  const hasNode = (id) => nodes[String(id)] !== undefined;
  const existingNodeIds = Object.keys(nodes).sort((a, b) => Number(a) - Number(b));
  const actions = [];
  const missingWorkflowNodes = [];

  const patchNode = (id, mutator, label = '') => {
    const k = String(id);

    if (!hasNode(k)) {
      missingWorkflowNodes.push({ id: k, label });
      return;
    }

    const node = clone(nodes[k]);
    mutator(node);

    actions.push({
      type: 'addNode',
      id: k,
      overwrite: true,
      node
    });
  };

  const isMissing = (v) => v === undefined || v === null || v === '';
  const isBadNumber = (v) => !Number.isFinite(v) || v <= 0;

  // ==================================================
  // ВХОДНЫЕ ПЕРЕМЕННЫЕ
  // ==================================================
  const startFrameFileName =
    src.startFrameFileName ??
    src.image ??
    src.imageFileName ??
    src.fileName;

  const positivePrompt =
    src.positivePrompt ??
    src.prompt ??
    src.clipPrompt ??
    src.chunksPositivePrompts;

  const negativePrompt =
    src.negativePrompt ??
    src.negativePrompts;

  const clipWidth = Number(
    src.clipWidth ??
    src.width
  );

  const clipHeight = Number(
    src.clipHeight ??
    src.height
  );

  const frameRate = Number(
    src.frameRate ??
    src.fps ??
    src.clipFrameRate ??
    24
  );

  const framesCount = Number(
    src.framesCount ??
    src.clipFramesCount ??
    src.length ??
    src.totalFrames ??
    src.chunksFramesCount
  );
  // ==================================================

  const missingFields = [];

  if (isMissing(startFrameFileName)) {
    missingFields.push('startFrameFileName | image | imageFileName | fileName');
  }

  if (isMissing(positivePrompt)) {
    missingFields.push('positivePrompt | prompt | clipPrompt | chunksPositivePrompts');
  }

  if (isMissing(negativePrompt)) {
    missingFields.push('negativePrompt | negativePrompts');
  }

  if (isBadNumber(clipWidth)) {
    missingFields.push('clipWidth | width');
  }

  if (isBadNumber(clipHeight)) {
    missingFields.push('clipHeight | height');
  }

  if (isBadNumber(frameRate)) {
    missingFields.push('frameRate | fps | clipFrameRate');
  }

  if (isBadNumber(framesCount)) {
    missingFields.push('framesCount | clipFramesCount | length | totalFrames | chunksFramesCount');
  }

  if (missingFields.length > 0) {
    return fail('Не хватает обязательных входных полей', {
      missingFields,
      src,
      resolvedValues: {
        startFrameFileName,
        positivePrompt,
        negativePrompt,
        clipWidth,
        clipHeight,
        frameRate,
        framesCount
      }
    });
  }

  // 16 = positive prompt
  patchNode(16, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.text = String(positivePrompt);
  }, 'Positive Prompt');

  // 11 = negative prompt
  patchNode(11, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.text = String(negativePrompt);
  }, 'Negative Prompt');

  // 166 = width
  patchNode(166, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(clipWidth);
  }, 'Width');

  // 167 = height
  patchNode(167, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(clipHeight);
  }, 'Height');

  // 169 = frames count
  patchNode(169, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Math.round(framesCount);
  }, 'Frames Count');

  // 164 = frame rate
  patchNode(164, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.value = Number(frameRate);
  }, 'Frame Rate');

  // 45 = first frame file name
  patchNode(45, (n) => {
    if (!n.inputs || typeof n.inputs !== 'object') n.inputs = {};
    n.inputs.image = String(startFrameFileName);
  }, 'First Frame File Name');

  if (missingWorkflowNodes.length > 0) {
    return fail('В workflow отсутствуют нужные ноды', {
      missingWorkflowNodes,
      existingNodeIds,
      actions
    });
  }

  return actions;
})() }}

