={{ (() => {
  const src = $('set d8swfnb44q clip params1').item.json || {};
  const workflowRaw = $json.workflow;

  const clone = (v) => JSON.parse(JSON.stringify(v));
  const root = typeof workflowRaw === 'string' ? JSON.parse(workflowRaw) : clone(workflowRaw);
  const nodes = root && root.prompt && typeof root.prompt === 'object' ? root.prompt : root;

  const hasNode = (id) => nodes && nodes[String(id)] !== undefined;
  const actions = [];

  const patchNode = (id, mutator) => {
    const k = String(id);
    if (!hasNode(k)) return;
    const node = clone(nodes[k]);
    mutator(node);
    actions.push({
      type: 'addNode',
      id: k,
      overwrite: true,
      node
    });
  };

  const parseArr = (v) => {
    if (Array.isArray(v)) return v;
    if (typeof v === 'string') {
      try {
        const p = JSON.parse(v);
        return Array.isArray(p) ? p : [];
      } catch {
        return [];
      }
    }
    return [];
  };

  // ========= ВХОДНЫЕ ПЕРЕМЕННЫЕ =========
  const prompts = parseArr(src.chunksPositivePrompts);
  const frames = parseArr(src.chunksFramesCount);

  const startFrameFileName = src.startFrameFileName;
  const negativePrompt = src.negativePrompt ?? src.negativePrompts ?? '';

  const clipWidth = Number(src.clipWidth);
  const clipHeight = Number(src.clipHeight);
  const clipAspectRatioRaw = String(src.clipAspectRatio);

  const highNoiseSize = Number(src.highNoiseSize ?? Math.max(clipWidth, clipHeight));
  const finalSize = Number(src.finalSize ?? Math.max(clipWidth, clipHeight));

  // Сколько кадров добавлять к чанкам со 2-го и далее (для компенсации overlap)
  const OVERLAP_COMPENSATION_FRAMES = Number(src.overlapCompensationFrames ?? 6);
  // ======================================

  // target chunks: explicit > длины массивов
  const explicitCount = Number(src.chunksCount ?? src.targetChunks ?? src.totalChunks);
  let targetChunks = Number.isInteger(explicitCount) && explicitCount > 0
    ? explicitCount
    : Math.max(prompts.length, frames.length, 1);

  targetChunks = Math.max(1, Math.min(6, targetChunks));

  // Удаляем лишние чанки > targetChunks
  for (let c = targetChunks + 1; c <= 6; c++) {
    const start = c * 100;
    const end = start + 99;
    for (let id = start; id <= end; id++) {
      if (hasNode(id)) {
        actions.push({ type: 'removeNode', nodeId: String(id) });
      }
    }
  }

  // Base patches
  if (startFrameFileName) {
    patchNode(6, (n) => { n.inputs.image = String(startFrameFileName); }); // Load Image
  }

  patchNode(31, (n) => { n.inputs.text = String(negativePrompt); }); // Negative_Prompt

  // Aspect ratio node
  const ratioKeys = ['1:1','4:3','3:2','5:4','16:9','16:10','21:9','2:1','1.85:1','2.39:1'];
  const clipAspectRatio = ratioKeys.includes(clipAspectRatioRaw) ? clipAspectRatioRaw : '16:9';

  patchNode(42, (n) => {
    if (Number.isFinite(clipWidth) && clipWidth > 0) n.inputs.width = Math.round(clipWidth);
    if (Number.isFinite(clipHeight) && clipHeight > 0) n.inputs.height = Math.round(clipHeight);
    for (const k of ratioKeys) n.inputs[k] = (k === clipAspectRatio);
  });

  if (Number.isFinite(highNoiseSize) && highNoiseSize > 0) {
    patchNode(43, (n) => { n.inputs.size = Math.round(highNoiseSize); }); // Set_High_Noise_Size
  }

  if (Number.isFinite(finalSize) && finalSize > 0) {
    patchNode(44, (n) => { n.inputs.size = Math.round(finalSize); }); // Set_Final_Size
  }

  // Chunk node id maps
  const promptId = (c) => (c === 1 ? 133 : c * 100 + 44); // 133,244,344...
  const framesId = (c) => (c === 1 ? 145 : c * 100 + 51); // 145,251,351...
  const finalId  = (c) => (c === 1 ? 139 : c * 100 + 39); // 139,239,339...

  // Patch prompts + frames (со 2-го чанка добавляем overlap compensation)
  for (let c = 1; c <= targetChunks; c++) {
    const p = prompts[c - 1];
    if (p !== undefined && p !== null && hasNode(promptId(c))) {
      patchNode(promptId(c), (n) => { n.inputs.value = String(p); });
    }

    const f = Number(frames[c - 1]);
    if (Number.isFinite(f) && f > 0 && hasNode(framesId(c))) {
      const extra = c === 1 ? 0 : Math.max(0, Math.round(OVERLAP_COMPENSATION_FRAMES));
      patchNode(framesId(c), (n) => { n.inputs.value = Math.round(f) + extra; });
    }
  }

  // save_output=true только у последнего чанка
  for (let c = 1; c <= targetChunks; c++) {
    if (hasNode(finalId(c))) {
      patchNode(finalId(c), (n) => { n.inputs.save_output = (c === targetChunks); });
    }
  }

  return actions;
})() }}

={{ (() => {
  const src = $('set x4305f6gs5 clip params').item.json || {};
  const workflowRaw = $json.workflow;

  const clone = (v) => JSON.parse(JSON.stringify(v));
  const root = typeof workflowRaw === 'string'
    ? JSON.parse(workflowRaw)
    : (workflowRaw && typeof workflowRaw === 'object' ? clone(workflowRaw) : {});
  const nodes = root && root.prompt && typeof root.prompt === 'object' ? root.prompt : root;

  const hasNode = (id) => nodes && nodes[String(id)] !== undefined;
  const actions = [];

  const pushNode = (id, node) => {
    actions.push({ type: 'addNode', id: String(id), overwrite: true, node });
  };

  const removeNode = (id) => {
    const k = String(id);
    if (!hasNode(k)) return;
    actions.push({ type: 'removeNode', nodeId: k });
  };

  const patchNode = (id, mutator) => {
    const k = String(id);
    if (!hasNode(k)) return;
    const node = clone(nodes[k]);
    node.inputs = node.inputs || {};
    mutator(node);
    pushNode(k, node);
  };

  const upsertNode = (id, factory, mutator) => {
    const k = String(id);
    const node = hasNode(k) ? clone(nodes[k]) : factory();
    node.inputs = node.inputs || {};
    mutator(node);
    pushNode(k, node);
  };

  const parseArr = (v, { splitPlainString = false } = {}) => {
    if (Array.isArray(v)) return v;
    if (v === undefined || v === null) return [];
    if (typeof v === 'string') {
      const s = v.trim();
      if (!s) return [];
      if (s[0] === '[') {
        try {
          const p = JSON.parse(s);
          return Array.isArray(p) ? p : [];
        } catch {}
      }
      if (splitPlainString) {
        return s.split(/\r?\n|,/).map((x) => x.trim()).filter(Boolean);
      }
      return [v];
    }
    return [];
  };

  const finiteNumber = (v, fallback) => {
    const n = Number(v);
    return Number.isFinite(n) ? n : fallback;
  };

  const positivePrompts = parseArr(src.chunksPositivePrompts ?? src.positivePrompts ?? src.prompts);
  const negativePrompts = parseArr(src.chunksNegativePrompts ?? src.chunkNegativePrompts ?? src.negativePrompts);
  const frames = parseArr(src.chunksFramesCount ?? src.framesCount ?? src.frames, { splitPlainString: true });

  const explicitCount = Number(src.chunksCount ?? src.targetChunks ?? src.totalChunks);
  let targetChunks = Number.isInteger(explicitCount) && explicitCount > 0
    ? explicitCount
    : Math.max(positivePrompts.length, negativePrompts.length, frames.length, 1);
  targetChunks = Math.max(1, Math.floor(targetChunks));

  const defaultFrames = Math.max(1, Math.round(finiteNumber(src.defaultFramesCount ?? src.framesDefault, 81)));
  const overlapFrames = Math.max(0, Math.round(finiteNumber(src.overlapFrames ?? src.overlap, 5)));
  const overlapCompensationFrames = Math.max(0, Math.round(finiteNumber(src.overlapCompensationFrames, overlapFrames)));
  const seedBase = Math.round(finiteNumber(src.noiseSeed ?? src.seed, 42));
  const chunkSeeds = parseArr(src.chunksSeeds ?? src.noiseSeeds, { splitPlainString: true });

  const promptFor = (c) => positivePrompts[c - 1] !== undefined && positivePrompts[c - 1] !== null
    ? String(positivePrompts[c - 1])
    : '';

  const negativeFor = (c) => {
    if (negativePrompts[c - 1] !== undefined && negativePrompts[c - 1] !== null) return String(negativePrompts[c - 1]);
    if (negativePrompts.length === 1 && negativePrompts[0] !== undefined && negativePrompts[0] !== null) return String(negativePrompts[0]);
    if (src.negativePrompt !== undefined && src.negativePrompt !== null) return String(src.negativePrompt);
    return '';
  };

  const framesFor = (c) => {
    const raw = frames[c - 1] !== undefined && frames[c - 1] !== null ? frames[c - 1] : defaultFrames;
    const base = Math.max(1, Math.round(finiteNumber(raw, defaultFrames)));
    return base + (c === 1 ? 0 : overlapCompensationFrames);
  };

  const seedFor = (c) => {
    const raw = chunkSeeds[c - 1];
    return Math.round(finiteNumber(raw, seedBase + c - 1));
  };

  const rawLoras = parseArr(
    src.additionalLoras ?? src.additionalLoraNames ?? src.loraNames ?? src.loras ?? src.additionalLoraName,
    { splitPlainString: true }
  );
  const defaultLoraStrength = finiteNumber(src.additionalLoraStrengthModel ?? src.additionalLoraStrength, 1.0000000000000002);
  const additionalLoras = rawLoras
    .map((x) => {
      if (x && typeof x === 'object') {
        const name = x.lora_name ?? x.loraName ?? x.name;
        return name ? { name: String(name), strength: finiteNumber(x.strength_model ?? x.strengthModel ?? x.strength, defaultLoraStrength) } : null;
      }
      const name = String(x ?? '').trim();
      return name ? { name, strength: defaultLoraStrength } : null;
    })
    .filter(Boolean);

  if (src.startFrameFileName) {
    patchNode('294', (n) => { n.inputs.image = String(src.startFrameFileName); });
  }

  const width = finiteNumber(src.clipWidth ?? src.width, NaN);
  const height = finiteNumber(src.clipHeight ?? src.height, NaN);
  if (Number.isFinite(width) && width > 0) patchNode('606', (n) => { n.inputs.value = Math.round(width); });
  if (Number.isFinite(height) && height > 0) patchNode('607', (n) => { n.inputs.value = Math.round(height); });

  const fps = finiteNumber(src.fps ?? src.clipFps, NaN);
  if (Number.isFinite(fps) && fps > 0) patchNode('630', (n) => { n.inputs.value = fps; });

  const steps = finiteNumber(src.steps, NaN);
  if (Number.isFinite(steps) && steps > 0) patchNode('609', (n) => { n.inputs.value = Math.round(steps); });

  const splitStep = finiteNumber(src.splitStep ?? src.split_step, NaN);
  if (Number.isFinite(splitStep) && splitStep > 0) patchNode('610', (n) => { n.inputs.value = Math.round(splitStep); });

  let highModelId = '670';
  for (let i = 0; i < additionalLoras.length; i++) {
    const id = String(700 + i);
    const inputModelId = highModelId;
    const lora = additionalLoras[i];

    upsertNode(id, () => ({
      inputs: {},
      class_type: 'LoraLoaderModelOnly',
      _meta: { title: `ADDITIONAL_LORA_NAME ${i + 1}` }
    }), (n) => {
      n.class_type = 'LoraLoaderModelOnly';
      n.inputs.lora_name = lora.name;
      n.inputs.strength_model = lora.strength;
      n.inputs.model = [inputModelId, 0];
      n._meta = n._meta || {};
      n._meta.title = `ADDITIONAL_LORA_NAME ${i + 1}`;
    });

    highModelId = id;
  }

  // If the base workflow already has old additional LoRA nodes, remove the ones
  // that are not requested for this run.
  for (let id = 700 + additionalLoras.length; id < 800; id++) {
    const k = String(id);
    if (!hasNode(k)) continue;
    const n = nodes[k];
    const title = n && n._meta && n._meta.title ? String(n._meta.title) : '';
    if (n && n.class_type === 'LoraLoaderModelOnly' && title.indexOf('ADDITIONAL_LORA_NAME') === 0) {
      removeNode(k);
    }
  }

  patchNode('623:297', (n) => { n.inputs.model = [highModelId, 0]; });

  const chunkSpec = (c) => {
    if (c === 1) return {
      frame: '696', positive: '623:596', negative: '623:598', wan: '623:595', highCfg: '623:597',
      noise: '623:599', highSampler: '623:603', disable: '623:601', lowCfg: '623:602',
      lowSampler: '623:604', decode: '623:600', overlap: null
    };
    if (c === 2) return {
      frame: '697', positive: '336:334', negative: '336:335', wan: '336:333', highCfg: '336:330',
      noise: '336:332', highSampler: '336:326', disable: '336:325', lowCfg: '336:331',
      lowSampler: '336:327', decode: '336:328', overlap: '336:329'
    };
    if (c === 3) return {
      frame: '698', positive: '644:675', negative: '644:676', wan: '644:678', highCfg: '644:674',
      noise: '644:677', highSampler: '644:679', disable: '644:680', lowCfg: '644:681',
      lowSampler: '644:682', decode: '644:684', overlap: '644:683'
    };

    const base = 8000 + (c - 4) * 20;
    return {
      frame: String(base), highCfg: String(base + 1), disable: String(base + 2), highSampler: String(base + 3),
      lowSampler: String(base + 4), decode: String(base + 5), overlap: String(base + 6), noise: String(base + 7),
      wan: String(base + 8), positive: String(base + 9), negative: String(base + 10), lowCfg: String(base + 11)
    };
  };

  const chunkNodeIds = (c) => {
    const s = chunkSpec(c);
    return [
      s.frame, s.positive, s.negative, s.wan, s.highCfg, s.noise,
      s.highSampler, s.disable, s.lowCfg, s.lowSampler, s.decode, s.overlap
    ].filter(Boolean);
  };

  // Remove chunk blocks that exist in the base workflow but are not needed for
  // this run. This prevents base 1.json from leaving a visible unused 3rd chunk
  // when only 1 or 2 chunks were requested.
  for (let c = targetChunks + 1; c <= 20; c++) {
    for (const id of chunkNodeIds(c)) {
      removeNode(id);
    }
  }

  const primitiveIntNode = (value, title) => ({ inputs: { value }, class_type: 'PrimitiveInt', _meta: { title } });
  const clipTextNode = (text) => ({ inputs: { text, clip: ['672', 0] }, class_type: 'CLIPTextEncode', _meta: { title: 'CLIP Text Encode (Prompt)' } });
  const randomNoiseNode = (seed) => ({ inputs: { noise_seed: seed }, class_type: 'RandomNoise', _meta: { title: 'RandomNoise' } });
  const disableNoiseNode = () => ({ inputs: {}, class_type: 'DisableNoise', _meta: { title: 'DisableNoise' } });
  const cfgNode = (modelId, wanId) => ({
    inputs: { cfg: 1, start_percent: 0, end_percent: 1, model: [modelId, 0], positive: [wanId, 0], negative: [wanId, 1] },
    class_type: 'ScheduledCFGGuidance',
    _meta: { title: 'Scheduled CFG Guidance' }
  });
  const samplerNode = (noiseId, cfgId, latentRef, sigmasIndex) => ({
    inputs: { noise: [noiseId, 0], guider: [cfgId, 0], sampler: ['623:299', 0], sigmas: ['623:128', sigmasIndex], latent_image: latentRef },
    class_type: 'SamplerCustomAdvanced',
    _meta: { title: 'SamplerCustomAdvanced' }
  });
  const decodeNode = (samplerId) => ({ inputs: { samples: [samplerId, 0], vae: ['673', 0] }, class_type: 'VAEDecode', _meta: { title: 'VAE Decode' } });
  const wanNode = (s, previousLowSamplerId) => {
    const inputs = {
      length: [s.frame, 0],
      motion_latent_count: 1,
      positive: [s.positive, 0],
      negative: [s.negative, 0],
      anchor_samples: ['295', 0]
    };
    if (previousLowSamplerId) inputs.prev_samples = [previousLowSamplerId, 0];
    return { inputs, class_type: 'WanImageToVideoSVIPro', _meta: { title: 'WanImageToVideoSVIPro' } };
  };
  const overlapNode = (sourceImages, decodeId) => ({
    inputs: { overlap: overlapFrames, overlap_side: 'source', overlap_mode: 'linear_blend', source_images: sourceImages, new_images: [decodeId, 0] },
    class_type: 'ImageBatchExtendWithOverlap',
    _meta: { title: 'Image Batch Extend With Overlap' }
  });

  let previousFinalImages = null;
  let previousLowSamplerId = null;

  for (let c = 1; c <= targetChunks; c++) {
    const s = chunkSpec(c);
    const frameCount = framesFor(c);
    const positiveText = promptFor(c);
    const negativeText = negativeFor(c);

    upsertNode(s.frame, () => primitiveIntNode(frameCount, `FRAMES_COUNT_CHUNK_${c}`), (n) => {
      n.class_type = 'PrimitiveInt';
      n.inputs.value = frameCount;
      n._meta = n._meta || {};
      n._meta.title = `FRAMES_COUNT_CHUNK_${c}`;
    });

    upsertNode(s.positive, () => clipTextNode(positiveText), (n) => {
      n.class_type = 'CLIPTextEncode';
      n.inputs.text = positiveText;
      n.inputs.clip = ['672', 0];
    });

    upsertNode(s.negative, () => clipTextNode(negativeText), (n) => {
      n.class_type = 'CLIPTextEncode';
      n.inputs.text = negativeText;
      n.inputs.clip = ['672', 0];
    });

    upsertNode(s.noise, () => randomNoiseNode(seedFor(c)), (n) => {
      n.class_type = 'RandomNoise';
      n.inputs.noise_seed = seedFor(c);
    });

    upsertNode(s.wan, () => wanNode(s, previousLowSamplerId), (n) => {
      n.class_type = 'WanImageToVideoSVIPro';
      n.inputs.length = [s.frame, 0];
      n.inputs.motion_latent_count = 1;
      n.inputs.positive = [s.positive, 0];
      n.inputs.negative = [s.negative, 0];
      n.inputs.anchor_samples = ['295', 0];
      if (previousLowSamplerId) n.inputs.prev_samples = [previousLowSamplerId, 0];
      else delete n.inputs.prev_samples;
    });

    upsertNode(s.highCfg, () => cfgNode(highModelId, s.wan), (n) => {
      n.class_type = 'ScheduledCFGGuidance';
      n.inputs.cfg = finiteNumber(src.highCfg ?? src.cfg, 1);
      n.inputs.start_percent = 0;
      n.inputs.end_percent = 1;
      n.inputs.model = [highModelId, 0];
      n.inputs.positive = [s.wan, 0];
      n.inputs.negative = [s.wan, 1];
    });

    upsertNode(s.highSampler, () => samplerNode(s.noise, s.highCfg, [s.wan, 2], 0), (n) => {
      n.class_type = 'SamplerCustomAdvanced';
      n.inputs.noise = [s.noise, 0];
      n.inputs.guider = [s.highCfg, 0];
      n.inputs.sampler = ['623:299', 0];
      n.inputs.sigmas = ['623:128', 0];
      n.inputs.latent_image = [s.wan, 2];
    });

    upsertNode(s.disable, () => disableNoiseNode(), (n) => {
      n.class_type = 'DisableNoise';
      n.inputs = {};
    });

    upsertNode(s.lowCfg, () => cfgNode('671', s.wan), (n) => {
      n.class_type = 'ScheduledCFGGuidance';
      n.inputs.cfg = finiteNumber(src.lowCfg ?? src.cfg, 1);
      n.inputs.start_percent = 0;
      n.inputs.end_percent = 1;
      n.inputs.model = ['671', 0];
      n.inputs.positive = [s.wan, 0];
      n.inputs.negative = [s.wan, 1];
    });

    upsertNode(s.lowSampler, () => samplerNode(s.disable, s.lowCfg, [s.highSampler, 0], 1), (n) => {
      n.class_type = 'SamplerCustomAdvanced';
      n.inputs.noise = [s.disable, 0];
      n.inputs.guider = [s.lowCfg, 0];
      n.inputs.sampler = ['623:299', 0];
      n.inputs.sigmas = ['623:128', 1];
      n.inputs.latent_image = [s.highSampler, 0];
    });

    upsertNode(s.decode, () => decodeNode(s.lowSampler), (n) => {
      n.class_type = 'VAEDecode';
      n.inputs.samples = [s.lowSampler, 0];
      n.inputs.vae = ['673', 0];
    });

    if (c === 1) {
      previousFinalImages = [s.decode, 0];
    } else {
      upsertNode(s.overlap, () => overlapNode(previousFinalImages, s.decode), (n) => {
        n.class_type = 'ImageBatchExtendWithOverlap';
        n.inputs.overlap = overlapFrames;
        n.inputs.overlap_side = 'source';
        n.inputs.overlap_mode = 'linear_blend';
        n.inputs.source_images = previousFinalImages;
        n.inputs.new_images = [s.decode, 0];
      });
      previousFinalImages = [s.overlap, 2];
    }

    previousLowSamplerId = s.lowSampler;
  }

  patchNode('656', (n) => {
    n.inputs.images = previousFinalImages;
    n.inputs.save_output = true;
    if (src.filenamePrefix ?? src.filename_prefix ?? src.outputPrefix) {
      n.inputs.filename_prefix = String(src.filenamePrefix ?? src.filename_prefix ?? src.outputPrefix);
    }
  });

  return actions;
})() }}

