   $('read visualSegment').item.json.generation_data.prompts.negativePrompt :

(()=>{

const defaultNegaitePrompt = 'Bright, oversaturated tones; overexposed; static; unclear or blurry details; subtitles; style or artistic work; painting or image; still/frozen frame; overall grayish appearance; worst quality; low quality; JPEG artifacts; ugly; incomplete or damaged; extra fingers; poorly drawn hands; poorly drawn face; deformed; disfigured; malformed limbs; fused fingers; motionless/still image; messy/cluttered background; three legs; many people in the background; walking backwards. do not animate the background'

const arr = []

// Removed "range" from this line
for (let i = 0; i < $('read visualSegment').item.json.generation_data.prompts.videoClipPrompts.length; i++) {
  arr.push(defaultNegaitePrompt)
}

return arr

})() }}

={{ (()=>{
let chunksFramesCount = []

const clipFps = $('get all workflow params').first().json.clipFps
const videoModelClipDurationLimitationMs = $('get all workflow params').first().json.videoModelLimitationOnTheGeneratedVideoDurationMs
const currentVisualDurationMs = $('Start').item.json.durMs

const needChunksToCoverWantedClipDuration =
Math.ceil(currentVisualDurationMs / videoModelClipDurationLimitationMs)

for (let i = 0; i < needChunksToCoverWantedClipDuration; i++) {
  const isLast = i === needChunksToCoverWantedClipDuration - 1

  if (!isLast) {
    chunksFramesCount.push(videoModelClipDurationLimitationMs / 1000 * clipFps + 1)
  } else {
    const tailMs = currentVisualDurationMs - i * videoModelClipDurationLimitationMs
    chunksFramesCount.push(Math.ceil(tailMs / 1000 * clipFps) + 1)
  }
}

return chunksFramesCount
})() }}

